using Ledgerly.Application.Expenses; using Microsoft.AspNetCore.Mvc; namespace Ledgerly.Api.Controllers; [ApiController][Route("api/organizations/{organizationId:guid}/expenses")] public sealed class ExpensesController:ControllerBase{ private readonly ExpenseService _s; public ExpensesController(ExpenseService s)=>_s=s; [HttpGet("{expenseId:guid}")] public async Task<IActionResult> Get(Guid organizationId,Guid expenseId,CancellationToken ct=default){var r=await _s.GetByIdAsync(organizationId,expenseId,ct);return r.IsFailure?NotFound(new{error=r.Error}):Ok(r.Value);} [HttpPost] public async Task<IActionResult> Create(Guid organizationId,[FromBody]CreateExpenseRequest req,CancellationToken ct=default){var r=await _s.CreateAsync(req,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPut("{expenseId:guid}/receipt")] public async Task<IActionResult> SetReceipt(Guid organizationId,Guid expenseId,[FromBody]SetExpenseReceiptRequest req,CancellationToken ct=default){var r=await _s.SetReceiptAsync(organizationId,expenseId,req,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{expenseId:guid}/post")] public async Task<IActionResult> Post(Guid organizationId,Guid expenseId,CancellationToken ct=default){var r=await _s.PostAsync(organizationId,expenseId,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{expenseId:guid}/void")] public async Task<IActionResult> Void(Guid organizationId,Guid expenseId,CancellationToken ct=default){var r=await _s.VoidAsync(organizationId,expenseId,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} }
